 4→import kotlin.test.*
 5→
 6→class InstantParsing {
 7→    @Test
 8→    fun testParsingInvalidInstants() {
 9→        fun parseInstantLikeJavaDoes(input: String): Instant =
10→            DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET.parse(input).apply {
11→                when {
12→                    hour == 24 && minute == 0 && second == 0 && nanosecond == 0 -> {
13→                        setDate(toLocalDate().plus(1, DateTimeUnit.DAY))
14→                        hour = 0
15→                    }
16→                    hour == 23 && minute == 59 && second == 60 -> second = 59
17→                }
18→            }.toInstantUsingOffset()
19→        fun formatTwoDigits(i: Int) = if (i < 10) "0$i" else "$i"
20→        for (hour in 23..25) {
21→            for (minute in listOf(0..5, 58..62).flatten()) {
22→                for (second in listOf(0..5, 58..62).flatten()) {
23→                    val input = "2020-03-16T${hour}:${formatTwoDigits(minute)}:${formatTwoDigits(second)}Z"
24→                    assertEquals(
25→                        runCatching { java.time.Instant.parse(input) }.getOrNull(),
26→                        runCatching { parseInstantLikeJavaDoes(input).toJavaInstant() }.getOrNull()
27→                    )
28→                }
29→            }
30→        }
31→    }
32→
33→}
